-- TABLE: tbl_report
-- Confidence: HIGH
-- Evidence: cron.php lines 30-32 â€” INSERT:
--   main_offer_id, main_offer_url, offer_clicks, report_date
--   cron.php line 21 â€” UPDATE: offer_clicks WHERE main_offer_id + report_date
--   cron.php line 19 â€” SELECT * FROM tbl_report WHERE report_date=? AND main_offer_id=?
--   Report.php line 13 â€” SELECT main_offer_id, main_offer_url,
--                          offer_clicks, report_date FROM tbl_report
--   UNIQUE on (main_offer_id, report_date): cron.php checks existence before
--   INSERT vs UPDATE â€” DB-level constraint makes this idempotent
-- =============================================================
CREATE TABLE IF NOT EXISTS `tbl_report` (
    `id`             INT          NOT NULL AUTO_INCREMENT,
    `main_offer_id`  INT              NULL,
    `main_offer_url` VARCHAR(255)     NULL,
    `offer_clicks`   INT          NOT NULL DEFAULT 0,
    `report_date`    DATE         NOT NULL,
    PRIMARY KEY (`id`),
    UNIQUE KEY `uq_offer_report_date` (`main_offer_id`, `report_date`),
    KEY `idx_report_offer` (`main_offer_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
